22: AccessLog::InstanceSharedPtr
23: FileAccessLogFactory::createAccessLogInstance(const Protobuf::Message& config,
24:                                               AccessLog::FilterPtr&& filter,
25:                                               Server::Configuration::FactoryContext& context) {
26:   const auto& fal_config = MessageUtil::downcastAndValidate<
27:       const envoy::extensions::access_loggers::file::v3::FileAccessLog&>(
28:       config, context.messageValidationVisitor());
29:   Formatter::FormatterPtr formatter;
30: 
31:   switch (fal_config.access_log_format_case()) {
32:   case envoy::extensions::access_loggers::file::v3::FileAccessLog::AccessLogFormatCase::kFormat:
33:     if (fal_config.format().empty()) {
34:       formatter = Formatter::HttpSubstitutionFormatUtils::defaultSubstitutionFormatter();
35:     } else {
36:       envoy::config::core::v3::SubstitutionFormatString sff_config;
37:       sff_config.mutable_text_format_source()->set_inline_string(fal_config.format());
38:       formatter = Formatter::SubstitutionFormatStringUtils::fromProtoConfig(sff_config, context);
39:     }
40:     break;
41:   case envoy::extensions::access_loggers::file::v3::FileAccessLog::AccessLogFormatCase::kJsonFormat:
42:     formatter = Formatter::SubstitutionFormatStringUtils::createJsonFormatter(
43:         fal_config.json_format(), false, false, false);
44:     break;
45:   case envoy::extensions::access_loggers::file::v3::FileAccessLog::AccessLogFormatCase::
46:       kTypedJsonFormat: {
47:     envoy::config::core::v3::SubstitutionFormatString sff_config;
48:     *sff_config.mutable_json_format() = fal_config.typed_json_format();
49:     formatter = Formatter::SubstitutionFormatStringUtils::fromProtoConfig(sff_config, context);
50:     break;
51:   }
52:   case envoy::extensions::access_loggers::file::v3::FileAccessLog::AccessLogFormatCase::kLogFormat:
53:     formatter =
54:         Formatter::SubstitutionFormatStringUtils::fromProtoConfig(fal_config.log_format(), context);
55:     break;
56:   case envoy::extensions::access_loggers::file::v3::FileAccessLog::AccessLogFormatCase::
57:       ACCESS_LOG_FORMAT_NOT_SET:
58:     formatter = Formatter::HttpSubstitutionFormatUtils::defaultSubstitutionFormatter();
59:     break;
60:   }
61: 
62:   Filesystem::FilePathAndType file_info{Filesystem::DestinationType::File, fal_config.path()};
63:   return std::make_shared<FileAccessLog>(file_info, std::move(filter), std::move(formatter),
64:                                          context.serverFactoryContext().accessLogManager());
65: }
