25: // [#protodoc-title: OpenTelemetry Access Log]
26: 
27: // Configuration for the built-in ``envoy.access_loggers.open_telemetry``
28: // :ref:`AccessLog <envoy_v3_api_msg_config.accesslog.v3.AccessLog>`. This configuration will
29: // populate `opentelemetry.proto.collector.v1.logs.ExportLogsServiceRequest.resource_logs <https://github.com/open-telemetry/opentelemetry-proto/blob/main/opentelemetry/proto/collector/logs/v1/logs_service.proto>`_.
30: // In addition, the request start time is set in the dedicated field.
31: // [#extension: envoy.access_loggers.open_telemetry]
32: // [#next-free-field: 15]
33: message OpenTelemetryAccessLogConfig {
34:   // [#comment:TODO(itamarkam): add 'filter_state_objects_to_log' to logs.]
35:   // Deprecated. Use ``grpc_service`` or ``http_service`` instead.
36:   grpc.v3.CommonGrpcAccessLogConfig common_config = 1
37:       [deprecated = true, (envoy.annotations.deprecated_at_minor_version) = "3.0"];
38: 
39:   // The upstream HTTP cluster that will receive OTLP logs via
40:   // `OTLP/HTTP <https://opentelemetry.io/docs/specs/otlp/#otlphttp>`_.
41:   // Note: Only one of ``common_config``, ``grpc_service``, or ``http_service`` may be used.
42:   //
43:   // .. note::
44:   //
45:   //   The ``request_headers_to_add`` property in the OTLP HTTP exporter service
46:   //   does not support the :ref:`format specifier <config_access_log_format>` as used for
47:   //   :ref:`HTTP access logging <config_access_log>`.
48:   //   The values configured are added as HTTP headers on the OTLP export request
49:   //   without any formatting applied.
50:   config.core.v3.HttpService http_service = 8;
51: 
52:   // The upstream gRPC cluster that will receive OTLP logs.
53:   // Note: Only one of ``common_config``, ``grpc_service``, or ``http_service`` may be used.
54:   // This field is preferred over ``common_config.grpc_service``.
55:   config.core.v3.GrpcService grpc_service = 9;
56: 
57:   // If specified, Envoy will not generate built-in resource labels
58:   // like ``log_name``, ``zone_name``, ``cluster_name``, ``node_name``.
59:   bool disable_builtin_labels = 5;
60: 
61:   // OpenTelemetry `Resource <https://github.com/open-telemetry/opentelemetry-proto/blob/main/opentelemetry/proto/logs/v1/logs.proto#L51>`_
62:   // attributes are filled with Envoy node info.
63:   // Example: ``resource_attributes { values { key: "region" value { string_value: "cn-north-7" } } }``.
64:   opentelemetry.proto.common.v1.KeyValueList resource_attributes = 4;
65: 
66:   // OpenTelemetry `LogResource <https://github.com/open-telemetry/opentelemetry-proto/blob/main/opentelemetry/proto/logs/v1/logs.proto>`_
67:   // fields, following `Envoy access logging formatting <https://www.envoyproxy.io/docs/envoy/latest/configuration/observability/access_log/usage>`_.
68:   //
69:   // See 'body' in the LogResource proto for more details.
70:   // Example: ``body { string_value: "%PROTOCOL%" }``.
71:   opentelemetry.proto.common.v1.AnyValue body = 2;
72: 
73:   // See 'attributes' in the LogResource proto for more details.
74:   // Example: ``attributes { values { key: "user_agent" value { string_value: "%REQ(USER-AGENT)%" } } }``.
75:   opentelemetry.proto.common.v1.KeyValueList attributes = 3;
76: 
77:   // Optional. Additional prefix to use on OpenTelemetry access logger stats. If empty, the stats will be rooted at
78:   // ``access_logs.open_telemetry_access_log.``. If non-empty, stats will be rooted at
79:   // ``access_logs.open_telemetry_access_log.<stat_prefix>.``.
80:   string stat_prefix = 6;
81: 
82:   // Specifies a collection of Formatter plugins that can be called from the access log configuration.
83:   // See the formatters extensions documentation for details.
84:   // [#extension-category: envoy.formatter]
85:   repeated config.core.v3.TypedExtensionConfig formatters = 7;
86: 
87:   string log_name = 10;
88: 
89:   // The interval for flushing access logs to the transport. Default: 1 second.
90:   google.protobuf.Duration buffer_flush_interval = 11;
91: 
92:   // Soft size limit in bytes for the access log buffer. When the buffer exceeds
93:   // this limit, logs will be flushed. Default: 16KB.
94:   google.protobuf.UInt32Value buffer_size_bytes = 12;
95: 
96:   // Additional filter state objects to log as attributes.
97:   repeated string filter_state_objects_to_log = 13;
98: 
99:   // Custom tags to include as log attributes.
100:   repeated type.tracing.v3.CustomTag custom_tags = 14;
101: }
