31:   // CEL expression configuration that modifies the evaluation behavior of the ``expression`` field.
32:   // If specified, string conversion, concatenation, and manipulation functions may be enabled
33:   // for the filter expression. See :ref:`CelExpressionConfig <envoy_v3_api_msg_config.core.v3.CelExpressionConfig>`
34:   // for more details.
35:   config.core.v3.CelExpressionConfig cel_config = 2;
36: }
