31: 
32: ComparisonFilter::ComparisonFilter(const envoy::config::accesslog::v3::ComparisonFilter& config,
33:                                    Runtime::Loader& runtime)
34:     : config_(config), runtime_(runtime) {}
35: 
36: bool ComparisonFilter::compareAgainstValue(uint64_t lhs) const {
37:   uint64_t value = config_.value().default_value();
38: 
39:   if (!config_.value().runtime_key().empty()) {
40:     value = runtime_.snapshot().getInteger(config_.value().runtime_key(), value);
41:   }
42: 
43:   switch (config_.op()) {
44:     PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
45:   case envoy::config::accesslog::v3::ComparisonFilter::GE:
46:     return lhs >= value;
47:   case envoy::config::accesslog::v3::ComparisonFilter::EQ:
48:     return lhs == value;
49:   case envoy::config::accesslog::v3::ComparisonFilter::LE:
50:     return lhs <= value;
51:   }
52:   IS_ENVOY_BUG("unexpected comparison op enum");
53:   return false;
54: }
55: 
56: FilterPtr FilterFactory::fromProto(const envoy::config::accesslog::v3::AccessLogFilter& config,
57:                                    Server::Configuration::FactoryContext& context) {
58:   Runtime::Loader& runtime = context.serverFactoryContext().runtime();
59:   Random::RandomGenerator& random = context.serverFactoryContext().api().randomGenerator();
60:   ProtobufMessage::ValidationVisitor& validation_visitor = context.messageValidationVisitor();
61:   switch (config.filter_specifier_case()) {
62:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kStatusCodeFilter:
63:     return FilterPtr{new StatusCodeFilter(config.status_code_filter(), runtime)};
64:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kDurationFilter:
65:     return FilterPtr{new DurationFilter(config.duration_filter(), runtime)};
66:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kNotHealthCheckFilter:
67:     return FilterPtr{new NotHealthCheckFilter()};
68:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kTraceableFilter:
69:     return FilterPtr{new TraceableRequestFilter()};
70:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kRuntimeFilter:
71:     return FilterPtr{new RuntimeFilter(config.runtime_filter(), runtime, random)};
72:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kAndFilter:
73:     return FilterPtr{new AndFilter(config.and_filter(), context)};
74:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kOrFilter:
75:     return FilterPtr{new OrFilter(config.or_filter(), context)};
76:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kHeaderFilter:
77:     return FilterPtr{new HeaderFilter(config.header_filter(), context.serverFactoryContext())};
78:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kResponseFlagFilter:
79:     MessageUtil::validate(config, validation_visitor);
80:     return FilterPtr{new ResponseFlagFilter(config.response_flag_filter())};
81:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kGrpcStatusFilter:
82:     MessageUtil::validate(config, validation_visitor);
83:     return FilterPtr{new GrpcStatusFilter(config.grpc_status_filter())};
84:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kMetadataFilter:
85:     return FilterPtr{new MetadataFilter(config.metadata_filter(), context.serverFactoryContext())};
86:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kLogTypeFilter:
87:     return FilterPtr{new LogTypeFilter(config.log_type_filter())};
88:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::kExtensionFilter:
89:     MessageUtil::validate(config, validation_visitor);
90:     {
91:       auto& factory =
92:           Config::Utility::getAndCheckFactory<ExtensionFilterFactory>(config.extension_filter());
93:       return factory.createFilter(config.extension_filter(), context);
94:     }
95:   case envoy::config::accesslog::v3::AccessLogFilter::FilterSpecifierCase::FILTER_SPECIFIER_NOT_SET:
96:     PANIC_DUE_TO_PROTO_UNSET;
97:   }
98:   IS_ENVOY_BUG("unexpected filter specifier value");
99:   return nullptr;
100: }
